// ========================================
// GL365 Auto-Journal: Event Normalizer
// ========================================
// Takes raw platform data and normalizes it into
// a standard GL365 journal entry format.
//
// Required output fields:
//   tenant_id, contact_phone, contact_email, contact_name,
//   source, event_type, raw_summary, raw_data
//
// This node should be customized per platform integration.

const input = $input.first().json;

// Default normalization — override per platform
const normalized = {
  tenant_id: input.tenant_id || input.metadata?.tenant_id || '',
  contact_phone: input.phone || input.customer_phone || input.attendee_phone || '',
  contact_email: input.email || input.customer_email || input.attendee_email || '',
  contact_name: input.name || input.customer_name || input.attendee_name || '',
  source: input.source || 'webhook',
  event_type: input.event_type || input.type || 'unknown',
  raw_summary: input.summary || input.description || JSON.stringify(input).substring(0, 200),
  raw_data: input,
  sentiment: input.sentiment || 'neutral',
  importance: input.importance || 'normal'
};

return [{ json: normalized }];

// Extract the AI-generated summary from OpenRouter response
const input = $input.first().json;
const prevData = $('Normalize Event').first().json;

let summary = '';
try {
  const choices = input.choices || [];
  summary = choices[0]?.message?.content || prevData.raw_summary;
} catch {
  summary = prevData.raw_summary;
}

// Clean up the summary
summary = summary.trim().replace(/^["']|["']$/g, '');

return [{
  json: {
    ...prevData,
    summary: summary
  }
}];

